{"content":"// Match history — persists recent games to localStorage
export interface MatchRecord {
  id: string;
  date: string;
  mode: string;
  result: 'win' | 'loss' | 'draw';
  playerScore: string;
  opponentScore: string;
  opponentName: string;
  dartsThrown: number;
  avgScore: number;
  highThrow: number;
  duration: number; // seconds
}

const HISTORY_KEY = 'neondarts_history';
const MAX_RECORDS = 50;

export class MatchHistoryManager {
  private records: MatchRecord[] = [];

  constructor() {
    this.load();
  }

  private load() {
    try {
      const raw = localStorage.getItem(HISTORY_KEY);
      if (raw) {
        this.records = JSON.parse(raw);
      }
    } catch {
      this.records = [];
    }
  }

  private save() {
    try {
      localStorage.setItem(HISTORY_KEY, JSON.stringify(this.records));
    } catch { /* ignore */ }
  }

  addRecord(record: Omit<MatchRecord, 'id' | 'date'>) {
    const fullRecord: MatchRecord = {
      ...record,
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      date: new Date().toISOString(),
    };
    this.records.unshift(fullRecord);
    if (this.records.length > MAX_RECORDS) {
      this.records = this.records.slice(0, MAX_RECORDS);
    }
    this.save();
  }

  getRecords(limit = 20): MatchRecord[] {
    return this.records.slice(0, limit);
  }

  getStats(): {
    totalGames: number;
    wins: number;
    losses: number;
    winRate: number;
    avgScore: number;
    bestAvg: number;
    totalDarts: number;
    favoriteMode: string;
  } {
    const total = this.records.length;
    const wins = this.records.filter(r => r.result === 'win').length;
    const losses = this.records.filter(r => r.result === 'loss').length;
    const allAvgs = this.records.map(r => r.avgScore).filter(a => a > 0);
    const avgScore = allAvgs.length > 0 ? allAvgs.reduce((a, b) => a + b, 0) / allAvgs.length : 0;
    const bestAvg = allAvgs.length > 0 ? Math.max(...allAvgs) : 0;
    const totalDarts = this.records.reduce((s, r) => s + r.dartsThrown, 0);

    // Find most played mode
    const modeCounts: Record<string, number> = {};
    this.records.forEach(r => {
      modeCounts[r.mode] = (modeCounts[r.mode] || 0) + 1;
    });
    let favoriteMode = 'None';
    let maxCount = 0;
    for (const [mode, count] of Object.entries(modeCounts)) {
      if (count > maxCount) {
        maxCount = count;
        favoriteMode = mode;
      }
    }

    return {
      totalGames: total,
      wins,
      losses,
      winRate: total > 0 ? Math.round((wins / total) * 100) : 0,
      avgScore: Math.round(avgScore),
      bestAvg: Math.round(bestAvg),
      totalDarts,
      favoriteMode,
    };
  }

  clearHistory() {
    this.records = [];
    this.save();
  }

  formatDate(isoString: string): string {
    const d = new Date(isoString);
    const month = d.toLocaleString('default', { month: 'short' });
    const day = d.getDate();
    const hour = d.getHours().toString().padStart(2, '0');
    const min = d.getMinutes().toString().padStart(2, '0');
    return `${month} ${day} ${hour}:${min}`;
  }
}
","path":"neon-darts/src/match-history.ts"}

{"content":"// Player profile — persistent name, avatar color, stats preferences
const PROFILE_KEY = 'neondarts_profile';

export interface PlayerProfile {
  nickname: string;
  avatarColor: string; // hex color
  preferredHand: 'right' | 'left';
  soundVolume: number; // 0-1
  musicVolume: number; // 0-1
  hapticEnabled: boolean;
  showHints: boolean;
}

const DEFAULT_PROFILE: PlayerProfile = {
  nickname: 'Player 1',
  avatarColor: '#00ffff',
  preferredHand: 'right',
  soundVolume: 0.8,
  musicVolume: 0.4,
  hapticEnabled: true,
  showHints: true,
};

export class ProfileManager {
  profile: PlayerProfile;

  constructor() {
    this.profile = { ...DEFAULT_PROFILE };
    this.load();
  }

  private load() {
    try {
      const raw = localStorage.getItem(PROFILE_KEY);
      if (raw) {
        const saved = JSON.parse(raw);
        this.profile = { ...DEFAULT_PROFILE, ...saved };
      }
    } catch {
      this.profile = { ...DEFAULT_PROFILE };
    }
  }

  save() {
    try {
      localStorage.setItem(PROFILE_KEY, JSON.stringify(this.profile));
    } catch { /* ignore */ }
  }

  setNickname(name: string) {
    this.profile.nickname = name.trim().slice(0, 16) || 'Player 1';
    this.save();
  }

  setAvatarColor(color: string) {
    this.profile.avatarColor = color;
    this.save();
  }

  setSoundVolume(vol: number) {
    this.profile.soundVolume = Math.max(0, Math.min(1, vol));
    this.save();
  }

  setMusicVolume(vol: number) {
    this.profile.musicVolume = Math.max(0, Math.min(1, vol));
    this.save();
  }

  toggleHaptic() {
    this.profile.hapticEnabled = !this.profile.hapticEnabled;
    this.save();
  }

  toggleHand() {
    this.profile.preferredHand = this.profile.preferredHand === 'right' ? 'left' : 'right';
    this.save();
  }

  toggleHints() {
    this.profile.showHints = !this.profile.showHints;
    this.save();
  }

  get nickname(): string {
    return this.profile.nickname;
  }

  readonly AVATAR_COLORS = [
    '#00ffff', '#ff00ff', '#00ff88', '#ff6600',
    '#ffff00', '#ff0066', '#8844ff', '#44ff44',
  ];

  cycleColor(): string {
    const idx = this.AVATAR_COLORS.indexOf(this.profile.avatarColor);
    const next = (idx + 1) % this.AVATAR_COLORS.length;
    this.setAvatarColor(this.AVATAR_COLORS[next]);
    return this.profile.avatarColor;
  }
}
","path":"neon-darts/src/profile.ts"}

{"content":"// Ambient particle system — floating neon particles, grid pulses
import {
  World,
  Group,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  AdditiveBlending,
  Vector3,
  BufferGeometry,
  Float32BufferAttribute,
  Points,
  PointsMaterial,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh | Points;
  velocity: Vector3;
  life: number;
  maxLife: number;
  baseY: number;
  phase: number;
}

export class ParticleSystem {
  private world: World;
  private group: Group;
  private particles: Particle[] = [];
  private dustCloud: Points | null = null;
  private dustPositions: Float32Array | null = null;
  private time = 0;

  constructor(world: World) {
    this.world = world;
    this.group = new Group();
    world.scene.add(this.group as any);
    this.createFloatingOrbs();
    this.createDustCloud();
  }

  private createFloatingOrbs() {
    const colors = ['#00ffff', '#ff00ff', '#00ff88', '#ff6600', '#8844ff', '#ffff00'];
    const orbGeo = new SphereGeometry(0.015, 6, 6);

    for (let i = 0; i < 40; i++) {
      const color = colors[Math.floor(Math.random() * colors.length)];
      const mat = new MeshBasicMaterial({
        color: new Color(color),
        transparent: true,
        opacity: 0.4 + Math.random() * 0.3,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(orbGeo, mat);

      const x = (Math.random() - 0.5) * 12;
      const y = 0.3 + Math.random() * 4;
      const z = -6 + Math.random() * 10;
      mesh.position.set(x, y, z);
      this.group.add(mesh);

      this.particles.push({
        mesh,
        velocity: new Vector3(
          (Math.random() - 0.5) * 0.1,
          (Math.random() - 0.5) * 0.05,
          (Math.random() - 0.5) * 0.05,
        ),
        life: Math.random() * 10,
        maxLife: 8 + Math.random() * 6,
        baseY: y,
        phase: Math.random() * Math.PI * 2,
      });
    }
  }

  private createDustCloud() {
    const count = 200;
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);
    const dustColors = [
      new Color('#00ffff'),
      new Color('#ff00ff'),
      new Color('#00ff88'),
    ];

    for (let i = 0; i < count; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 16;
      positions[i * 3 + 1] = Math.random() * 5;
      positions[i * 3 + 2] = -8 + Math.random() * 12;

      const c = dustColors[Math.floor(Math.random() * dustColors.length)];
      colors[i * 3] = c.r;
      colors[i * 3 + 1] = c.g;
      colors[i * 3 + 2] = c.b;
    }

    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
    geo.setAttribute('color', new Float32BufferAttribute(colors, 3));

    const mat = new PointsMaterial({
      size: 0.02,
      vertexColors: true,
      transparent: true,
      opacity: 0.25,
      blending: AdditiveBlending,
      depthWrite: false,
    });

    this.dustCloud = new Points(geo, mat);
    this.dustPositions = positions;
    this.group.add(this.dustCloud);
  }

  update(dt: number) {
    this.time += dt;

    // Animate floating orbs
    for (const p of this.particles) {
      p.life += dt;
      const mesh = p.mesh as Mesh;

      // Gentle floating motion
      mesh.position.y = p.baseY + Math.sin(this.time * 0.5 + p.phase) * 0.3;
      mesh.position.x += p.velocity.x * dt;
      mesh.position.z += p.velocity.z * dt;

      // Pulse opacity
      const mat = mesh.material as MeshBasicMaterial;
      mat.opacity = (0.3 + Math.sin(this.time * 1.5 + p.phase) * 0.2);

      // Wrap around bounds
      if (mesh.position.x > 7) mesh.position.x = -7;
      if (mesh.position.x < -7) mesh.position.x = 7;
      if (mesh.position.z > 4) mesh.position.z = -6;
      if (mesh.position.z < -8) mesh.position.z = 4;

      // Scale pulse
      const s = 0.8 + Math.sin(this.time * 2 + p.phase * 2) * 0.3;
      mesh.scale.set(s, s, s);
    }

    // Animate dust cloud
    if (this.dustCloud && this.dustPositions) {
      const positions = this.dustPositions;
      for (let i = 0; i < positions.length / 3; i++) {
        positions[i * 3 + 1] += dt * 0.05; // Slow rise
        if (positions[i * 3 + 1] > 5) positions[i * 3 + 1] = 0;
      }
      (this.dustCloud.geometry.attributes.position as any).needsUpdate = true;

      // Rotate dust cloud slowly
      this.dustCloud.rotation.y += dt * 0.02;
    }
  }

  // Burst effect when something exciting happens
  burst(position: Vector3, color: string, count = 12) {
    const burstGeo = new SphereGeometry(0.01, 4, 4);
    const mat = new MeshBasicMaterial({
      color: new Color(color),
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
    });

    for (let i = 0; i < count; i++) {
      const mesh = new Mesh(burstGeo, mat.clone());
      mesh.position.copy(position);
      this.group.add(mesh);

      const dir = new Vector3(
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
      ).normalize().multiplyScalar(0.5 + Math.random() * 1.5);

      const startTime = this.time;
      const burstLife = 0.6 + Math.random() * 0.4;

      const animate = () => {
        const elapsed = this.time - startTime;
        if (elapsed > burstLife) {
          this.group.remove(mesh);
          return;
        }
        const t = elapsed / burstLife;
        mesh.position.x += dir.x * 0.016 * (1 - t);
        mesh.position.y += dir.y * 0.016 * (1 - t) - 0.005;
        mesh.position.z += dir.z * 0.016 * (1 - t);
        (mesh.material as MeshBasicMaterial).opacity = 0.8 * (1 - t);
        mesh.scale.setScalar(1 - t * 0.5);
        requestAnimationFrame(animate);
      };
      requestAnimationFrame(animate);
    }
  }
}
